export interface ApiMembership {
  id: string;
  apiId: string;
  userId: string;
  role: string;
  referenceType: string;
  referenceId: string;
  isApiMember(): boolean;
}

export class ApiMembershipImpl implements ApiMembership {
  id: string;
  apiId: string;
  userId: string;
  role: string;
  referenceType: string;
  referenceId: string;

  constructor(
    id: string,
    apiId: string,
    userId: string,
    role: string,
    referenceType: string,
    referenceId: string
  ) {
    this.id = id;
    this.apiId = apiId;
    this.userId = userId;
    this.role = role;
    this.referenceType = referenceType;
    this.referenceId = referenceId;
  }

  isApiMember(): boolean {
    return this.referenceType === 'API' && this.referenceId === this.apiId;
  }
}
